import React, { useEffect, useState } from "react";

const CheckIcon = () => (
  <svg width="28" height="28" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="2"/>
    <path d="M8 12l3 3 5-5" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
  </svg>
);

const AlertIcon = () => (
  <svg width="28" height="28" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="2"/>
    <line x1="12" y1="8" x2="12" y2="12" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
    <circle cx="12" cy="16" r="1" fill="currentColor"/>
  </svg>
);

const CrossIcon = () => (
  <svg width="28" height="28" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="2"/>
    <path d="M15 9l-6 6M9 9l6 6" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
  </svg>
);

const WaveIcon = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M2 12h2M6 6v12M10 9v6M14 4v16M18 8v8M22 12h-2" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
  </svg>
);

const BrainIcon = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 4C9 4 7 6 7 8c-2 0-4 1.5-4 4s2 4 4 4v2h10v-2c2 0 4-1.5 4-4s-2-4-4-4c0-2-2-4-5-4z" stroke="currentColor" strokeWidth="2" strokeLinejoin="round"/>
    <line x1="12" y1="8" x2="12" y2="16" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
    <line x1="9" y1="11" x2="15" y2="11" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
  </svg>
);

const DownloadIcon = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M12 3v12M8 11l4 4 4-4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
    <path d="M3 17v2a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-2" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
  </svg>
);

function ProgressBar({ label, value, color, delay = 0 }) {
  const [width, setWidth] = useState(0);
  useEffect(() => {
    const t = setTimeout(() => setWidth(Math.min(100, Math.max(0, value))), 400 + delay);
    return () => clearTimeout(t);
  }, [value, delay]);

  return (
    <div className="progress-wrap">
      <div className="progress-label">
        <span>{label}</span>
        <span style={{ fontWeight: 600 }}>{value?.toFixed(1)}%</span>
      </div>
      <div className="progress-track">
        <div className="progress-fill" style={{ width: `${width}%`, background: color }} />
      </div>
    </div>
  );
}

export default function ResultCard({ data }) {
  if (!data) return null;

  const isGranted = data.access === "Granted";
  const isFake = data.status?.toLowerCase().includes("fake");

  const accent = isGranted ? "#06d6a0" : isFake ? "#f72585" : "#ffd166";
  const badgeClass = isGranted ? "badge-green" : isFake ? "badge-red" : "badge-yellow";
  const StatusIcon = isGranted ? CheckIcon : isFake ? AlertIcon : CrossIcon;

  return (
    <div className="result-card-wrap">

      {/* Status Banner */}
      <div className="result-banner" style={{ borderLeftColor: accent }}>
        <div className="result-banner-left">
          <span className="result-icon" style={{ color: accent }}>
            <StatusIcon />
          </span>
          <div>
            <h2 className="result-status" style={{ color: accent }}>{data.status}</h2>
            {data.reason && <p className="result-reason">{data.reason}</p>}
          </div>
        </div>
        <span className={`badge ${badgeClass}`} style={{ fontSize: "0.95rem", padding: "8px 20px" }}>
          Access {data.access}
        </span>
      </div>

      {/* Stats Row */}
      <div className="stats-row">
        <div className="stat-card">
          <div className="stat-value" style={{ color: "var(--cyan)" }}>{data.similarity?.toFixed(1)}%</div>
          <div className="stat-label">Similarity</div>
        </div>
        <div className="stat-card">
          <div className="stat-value" style={{ color: "var(--green)" }}>{data.real_prob?.toFixed(1)}%</div>
          <div className="stat-label">Real Prob.</div>
        </div>
        <div className="stat-card">
          <div className="stat-value" style={{ color: "var(--pink)" }}>{data.fake_prob?.toFixed(1)}%</div>
          <div className="stat-label">Fake Prob.</div>
        </div>
        {data.distance != null && (
          <div className="stat-card">
            <div className="stat-value" style={{ color: "var(--yellow)" }}>{data.distance}</div>
            <div className="stat-label">Distance</div>
          </div>
        )}
      </div>

      {/* Progress Bars */}
      <div className="result-section">
        <h3 className="section-title">Analysis Metrics</h3>
        <ProgressBar label="Speaker Similarity"     value={data.similarity} color="linear-gradient(90deg,#4361ee,#7b2ff7)" delay={0} />
        <ProgressBar label="Real Voice Probability" value={data.real_prob}  color="linear-gradient(90deg,#06d6a0,#059669)" delay={120} />
        <ProgressBar label="Deepfake Probability"   value={data.fake_prob}  color="linear-gradient(90deg,#f72585,#7b2ff7)" delay={240} />
      </div>

      {/* Spectrograms */}
      {(data.reg_spec || data.login_spec) && (
        <div className="result-section">
          <h3 className="section-title" style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <WaveIcon /> Voice Spectrograms
          </h3>
          <div className="spec-grid">
            {data.reg_spec && (
              <div className="spec-item">
                <p className="spec-label">Registered Voice</p>
                <img src={data.reg_spec} alt="Registered spectrogram" className="spec-img" />
              </div>
            )}
            {data.login_spec && (
              <div className="spec-item">
                <p className="spec-label">Login Voice</p>
                <img src={data.login_spec} alt="Login spectrogram" className="spec-img" />
              </div>
            )}
          </div>
        </div>
      )}

      {/* GradCAM */}
      {data.grad_img && (
        <div className="result-section gradcam-section">
          <h3 className="section-title" style={{ color: "var(--cyan)", display: "flex", alignItems: "center", gap: 8 }}>
            <BrainIcon /> Deepfake Explanation (GradCAM)
          </h3>
          <p className="section-desc">
            Highlights which audio regions triggered the deepfake detection model.
          </p>
          <img src={data.grad_img} alt="GradCAM explanation" className="spec-img" />
        </div>
      )}

      {/* Actions */}
      <div className="result-actions">
        {data.report && (
          <a href={data.report} target="_blank" rel="noreferrer" className="btn btn-primary">
            <DownloadIcon /> Download Report
          </a>
        )}
      </div>

    </div>
  );
}
